127	function toLegacySessionStatus(
128	  status: OrchestrationSessionStatus,
129	): "connecting" | "ready" | "running" | "error" | "closed" {
130	  switch (status) {
131	    case "starting":
132	      return "connecting";
133	    case "running":
134	      return "running";
135	    case "error":
136	      return "error";
137	    case "ready":
138	    case "interrupted":
139	      return "ready";
140	    case "idle":
141	    case "stopped":
