# Custom Theme System — T3 Code

## Context

The app already has a light/dark/system mode toggle (`apps/web/src/hooks/useTheme.ts`) that
toggles the `.dark` class on `<html>` and reads Tailwind's `@variant dark` CSS rules.
The task adds a **named colour-palette system** ("t3-dark", "t3-light", "t3-midnight") on
top of that infrastructure. Each named theme ships its own background, foreground, accent,
sidebar, editor, terminal, and status-bar colours. Selecting a theme persists the choice to
localStorage, applies CSS custom properties directly via `element.style.setProperty()`
(inline-style precedence beats `:root` and `@variant dark` rules), and toggles `.dark`
appropriately. A `ThemeProvider` context + `useColorTheme` hook expose the selection to the
React tree; a new `ThemeSelector` component renders preview swatches in the Settings page.

**Constraint:** no new dependencies; no build-config changes.

---

## Critical Files

| File | Action |
|---|---|
| `packages/shared/src/theme.ts` | **Create** — theme types + 3 built-in definitions |
| `packages/shared/package.json` | **Modify** — add `./theme` subpath export |
| `apps/web/src/components/ThemeProvider.tsx` | **Create** — context provider + `useColorTheme` hook |
| `apps/web/src/components/ThemeSelector.tsx` | **Create** — swatch UI component |
| `apps/web/src/index.css` | **Modify** — declare default `--theme-*` fallback vars in `:root` |
| `apps/web/src/router.ts` | **Modify** — wrap children with `ThemeProvider` |
| `apps/web/src/routes/_chat.settings.tsx` | **Modify** — add `ThemeSelector` to Appearance section |

---

## Step-by-Step Implementation

### Step 1 — `packages/shared/src/theme.ts` (new file)

Pure TypeScript, no Effect runtime needed.

```ts
export interface ThemeColors {
  background: string;   // page / window background
  foreground: string;   // primary text
  accent: string;       // brand highlight / primary interactive
  sidebar: string;      // sidebar panel background
  editor: string;       // code editor surface
  terminal: string;     // terminal surface
  statusBar: string;    // status-bar strip
}

export interface ThemeDefinition {
  readonly id: string;
  readonly label: string;
  readonly description: string;
  readonly isDark: boolean;
  readonly colors: ThemeColors;
}

export type BuiltInThemeId = "t3-dark" | "t3-light" | "t3-midnight";
export const DEFAULT_COLOR_THEME_ID: BuiltInThemeId = "t3-dark";

export const BUILT_IN_THEMES: readonly ThemeDefinition[] = [
  {
    id: "t3-light" satisfies BuiltInThemeId,
    label: "T3 Light",
    description: "Clean light theme with T3's signature purple accent.",
    isDark: false,
    colors: {
      background: "oklch(1 0 0)",
      foreground: "oklch(0.296 0.007 286)",
      accent:     "oklch(0.488 0.217 264)",
      sidebar:    "oklch(0.982 0.002 247)",
      editor:     "oklch(1 0 0)",
      terminal:   "oklch(0.982 0.002 247)",
      statusBar:  "oklch(0.961 0.003 247)",
    },
  },
  {
    id: "t3-dark" satisfies BuiltInThemeId,
    label: "T3 Dark",
    description: "Default dark theme with T3's signature purple accent.",
    isDark: true,
    colors: {
      background: "oklch(0.087 0.002 286)",
      foreground: "oklch(0.957 0.003 286)",
      accent:     "oklch(0.588 0.217 264)",
      sidebar:    "oklch(0.072 0.002 286)",
      editor:     "oklch(0.095 0.002 286)",
      terminal:   "oklch(0.087 0.002 286)",
      statusBar:  "oklch(0.072 0.002 286)",
    },
  },
  {
    id: "t3-midnight" satisfies BuiltInThemeId,
    label: "T3 Midnight",
    description: "Deep midnight theme with cool blue-tinted shadows.",
    isDark: true,
    colors: {
      background: "oklch(0.13 0.035 264)",
      foreground: "oklch(0.88 0.012 264)",
      accent:     "oklch(0.65 0.195 280)",
      sidebar:    "oklch(0.09 0.03 264)",
      editor:     "oklch(0.145 0.04 264)",
      terminal:   "oklch(0.075 0.02 264)",
      statusBar:  "oklch(0.10 0.035 264)",
    },
  },
];

export function getBuiltInThemeById(id: string): ThemeDefinition {
  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) throw new Error(`Unknown color theme: ${id}`);
  return theme;
}

export function isBuiltInThemeId(value: unknown): value is BuiltInThemeId {
  return value === "t3-dark" || value === "t3-light" || value === "t3-midnight";
}
```

---

### Step 2 — `packages/shared/package.json`

Add one entry in the `"exports"` object (after `"./Net"`):

```json
"./theme": {
  "types": "./src/theme.ts",
  "import": "./src/theme.ts"
}
```

---

### Step 3 — `apps/web/src/components/ThemeProvider.tsx` (new file)

Co-locates the context, provider, hook, and the CSS application logic.
Mirrors the module-level eager-apply pattern from `hooks/useTheme.ts` so the
selected theme is applied _before_ React renders (no flash).

```tsx
import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_COLOR_THEME_ID,
  type BuiltInThemeId,
  type ThemeDefinition,
  getBuiltInThemeById,
  isBuiltInThemeId,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:color-theme";

// ── helpers ──────────────────────────────────────────────────────────────────

function getStoredThemeId(): BuiltInThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  return isBuiltInThemeId(raw) ? raw : DEFAULT_COLOR_THEME_ID;
}

function applyColorTheme(theme: ThemeDefinition, suppressTransitions = false): void {
  const el = document.documentElement;
  if (suppressTransitions) el.classList.add("no-transitions");

  // Override the key "seed" CSS custom properties inline.
  // Inline style wins over :root and @variant dark CSS rules.
  el.style.setProperty("--background", theme.colors.background);
  el.style.setProperty("--foreground", theme.colors.foreground);
  el.style.setProperty("--primary",    theme.colors.accent);
  el.style.setProperty("--ring",       theme.colors.accent);

  // New theme-specific surface variables (used by components that opt in).
  el.style.setProperty("--theme-sidebar",    theme.colors.sidebar);
  el.style.setProperty("--theme-editor",     theme.colors.editor);
  el.style.setProperty("--theme-terminal",   theme.colors.terminal);
  el.style.setProperty("--theme-statusbar",  theme.colors.statusBar);

  // Drive the data attribute (useful for CSS :has() hooks and testing).
  el.dataset.colorTheme = theme.id;

  // Toggle Tailwind's .dark class so dark: utilities still work.
  el.classList.toggle("dark", theme.isDark);

  if (suppressTransitions) {
    el.offsetHeight; // force reflow
    requestAnimationFrame(() => el.classList.remove("no-transitions"));
  }
}

// Eager apply on module load – prevents colour flash before React mounts.
applyColorTheme(getBuiltInThemeById(getStoredThemeId()));

// ── context ───────────────────────────────────────────────────────────────────

interface ColorThemeContextValue {
  themeId: BuiltInThemeId;
  theme: ThemeDefinition;
  setColorTheme: (id: BuiltInThemeId) => void;
  allThemes: readonly ThemeDefinition[];
}

const ColorThemeContext = createContext<ColorThemeContextValue | null>(null);

// ── provider ──────────────────────────────────────────────────────────────────

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [themeId, setThemeId] = useState<BuiltInThemeId>(getStoredThemeId);

  const setColorTheme = useCallback((id: BuiltInThemeId) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyColorTheme(getBuiltInThemeById(id), true);
    setThemeId(id);
  }, []);

  // Keep DOM in sync on mount (handles external localStorage changes via other tabs).
  useEffect(() => {
    applyColorTheme(getBuiltInThemeById(themeId));
  }, [themeId]);

  return (
    <ColorThemeContext.Provider
      value={{
        themeId,
        theme: getBuiltInThemeById(themeId),
        setColorTheme,
        allThemes: BUILT_IN_THEMES,
      }}
    >
      {children}
    </ColorThemeContext.Provider>
  );
}

// ── hook ──────────────────────────────────────────────────────────────────────

export function useColorTheme(): ColorThemeContextValue {
  const ctx = useContext(ColorThemeContext);
  if (!ctx) throw new Error("useColorTheme must be used within <ThemeProvider>");
  return ctx;
}
```

> **Note on naming:** The existing `hooks/useTheme.ts` handles `"light" | "dark" | "system"`
> (OS-level colour scheme). This new hook handles named palette themes. Naming them
> differently avoids ambiguity; both can coexist.

---

### Step 4 — `apps/web/src/components/ThemeSelector.tsx` (new file)

Mirrors the existing radio-style selector in the Settings Appearance section.
Shows three coloured swatches (background · accent · sidebar) per theme.

```tsx
import { useColorTheme } from "./ThemeProvider";
import { cn } from "~/lib/utils";

export function ThemeSelector() {
  const { themeId, setColorTheme, allThemes } = useColorTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {allThemes.map((theme) => {
        const selected = themeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setColorTheme(theme.id as Parameters<typeof setColorTheme>[0])}
            className={cn(
              "flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
          >
            <div className="flex items-center gap-3">
              {/* Preview swatches: background · accent · sidebar */}
              <div className="flex gap-1" aria-hidden="true">
                {[theme.colors.background, theme.colors.accent, theme.colors.sidebar].map(
                  (color, i) => (
                    <span
                      key={i}
                      className="block h-4 w-4 rounded-full ring-1 ring-inset ring-black/10 dark:ring-white/10"
                      style={{ background: color }}
                    />
                  ),
                )}
              </div>
              <span className="flex flex-col">
                <span className="text-sm font-medium">{theme.label}</span>
                <span className="text-xs">{theme.description}</span>
              </span>
            </div>
            {selected && (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}
```

---

### Step 5 — `apps/web/src/index.css`

Inside the existing `:root` block (after the last existing variable, before the `@variant dark`
block), add the four new fallback variables so components that consume them get sensible
defaults even before a theme is applied:

```css
  /* Color theme surface variables (overridden at runtime by ThemeProvider) */
  --theme-sidebar:   var(--card);
  --theme-editor:    var(--background);
  --theme-terminal:  var(--background);
  --theme-statusbar: var(--card);
```

---

### Step 6 — `apps/web/src/router.ts`

Import `ThemeProvider` and add it as the innermost wrapper so it has access to the
QueryClient context if it ever needs to, and theme CSS vars are applied before any
route component renders:

```ts
import { ThemeProvider } from "./components/ThemeProvider";

// Inside createRouter:
Wrap: ({ children }) =>
  createElement(
    QueryClientProvider,
    { client: queryClient },
    createElement(
      StoreProvider,
      null,
      createElement(ThemeProvider, null, children),
    ),
  ),
```

---

### Step 7 — `apps/web/src/routes/_chat.settings.tsx`

Add a new "Color Theme" sub-section inside the existing Appearance `<section>`, immediately
after the closing `</p>` of the "Active theme" line and before the closing `</section>`.

