---

## Step-by-Step Implementation

### Step 1 — `packages/shared/src/theme.ts` (new file)

Pure TypeScript, no Effect runtime needed.

```ts
export interface ThemeColors {
  background: string;   // page / window background
  foreground: string;   // primary text
  accent: string;       // brand highlight / primary interactive
  sidebar: string;      // sidebar panel background
  editor: string;       // code editor surface
  terminal: string;     // terminal surface
  statusBar: string;    // status-bar strip
}

export interface ThemeDefinition {
  readonly id: string;
  readonly label: string;
  readonly description: string;
  readonly isDark: boolean;
  readonly colors: ThemeColors;
}

export type BuiltInThemeId = "t3-dark" | "t3-light" | "t3-midnight";
export const DEFAULT_COLOR_THEME_ID: BuiltInThemeId = "t3-dark";

export const BUILT_IN_THEMES: readonly ThemeDefinition[] = [
  {
    id: "t3-light" satisfies BuiltInThemeId,
    label: "T3 Light",
    description: "Clean light theme with T3's signature purple accent.",
    isDark: false,
    colors: {
      background: "oklch(1 0 0)",
      foreground: "oklch(0.296 0.007 286)",
      accent:     "oklch(0.488 0.217 264)",
      sidebar:    "oklch(0.982 0.002 247)",
      editor:     "oklch(1 0 0)",
      terminal:   "oklch(0.982 0.002 247)",
      statusBar:  "oklch(0.961 0.003 247)",
    },
  },
  {
    id: "t3-dark" satisfies BuiltInThemeId,
    label: "T3 Dark",
    description: "Default dark theme with T3's signature purple accent.",
    isDark: true,
    colors: {
      background: "oklch(0.087 0.002 286)",
      foreground: "oklch(0.957 0.003 286)",
      accent:     "oklch(0.588 0.217 264)",
      sidebar:    "oklch(0.072 0.002 286)",
      editor:     "oklch(0.095 0.002 286)",
      terminal:   "oklch(0.087 0.002 286)",
      statusBar:  "oklch(0.072 0.002 286)",
    },
  },
  {
    id: "t3-midnight" satisfies BuiltInThemeId,
    label: "T3 Midnight",
    description: "Deep midnight theme with cool blue-tinted shadows.",
    isDark: true,
    colors: {
      background: "oklch(0.13 0.035 264)",
      foreground: "oklch(0.88 0.012 264)",
      accent:     "oklch(0.65 0.195 280)",
      sidebar:    "oklch(0.09 0.03 264)",
      editor:     "oklch(0.145 0.04 264)",
      terminal:   "oklch(0.075 0.02 264)",
      statusBar:  "oklch(0.10 0.035 264)",
    },
  },
];

export function getBuiltInThemeById(id: string): ThemeDefinition {
  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) throw new Error(`Unknown color theme: ${id}`);
  return theme;
}

export function isBuiltInThemeId(value: unknown): value is BuiltInThemeId {
