/**
 * ThemeSelector — radio-group component that lets the user pick a named
 * colour-palette theme.  Renders a preview swatch strip (background · accent ·
 * sidebar) alongside each theme's label and description, matching the styling
 * of the existing light/dark/system selector in the Settings Appearance section.
 */

import { useColorTheme } from "./ThemeProvider";
import { cn } from "~/lib/utils";
import { type BuiltInThemeId } from "@t3tools/shared/theme";

export function ThemeSelector() {
  const { themeId, setColorTheme, allThemes } = useColorTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {allThemes.map((theme) => {
        const selected = themeId === theme.id;

        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setColorTheme(theme.id as BuiltInThemeId)}
            className={cn(
              "flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
          >
            <div className="flex items-center gap-3">
              {/* Preview swatches: background · accent · sidebar */}
              <div className="flex gap-1" aria-hidden="true">
                {([theme.colors.background, theme.colors.accent, theme.colors.sidebar] as const).map(
                  (color, i) => (
                    <span
                      key={i}
                      className="block h-4 w-4 shrink-0 rounded-full ring-1 ring-inset ring-black/10 dark:ring-white/10"
                      style={{ background: color }}
                    />
                  ),
                )}
              </div>

              <span className="flex flex-col">
                <span className="text-sm font-medium">{theme.label}</span>
                <span className="text-xs">{theme.description}</span>
              </span>
            </div>

            {selected ? (
              <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

