/**
 * Named colour-palette theme system.
 *
 * Applies CSS custom properties via element.style.setProperty() (inline style),
 * which takes precedence over :root defaults and @variant dark rules — no CSS
 * specificity tricks required.
 *
 * The module-level eager apply (bottom of the helpers section) mirrors the
 * pattern in hooks/useTheme.ts to prevent a flash of default colours before
 * React mounts.
 */

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
  type ReactNode,
} from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_COLOR_THEME_ID,
  getBuiltInThemeById,
  isBuiltInThemeId,
  type BuiltInThemeId,
  type ThemeDefinition,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:color-theme";

// ── helpers ──────────────────────────────────────────────────────────────────

function getStoredThemeId(): BuiltInThemeId {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return isBuiltInThemeId(raw) ? raw : DEFAULT_COLOR_THEME_ID;
  } catch {
    return DEFAULT_COLOR_THEME_ID;
  }
}

function applyColorTheme(theme: ThemeDefinition, suppressTransitions = false): void {
  const el = document.documentElement;

  if (suppressTransitions) {
    el.classList.add("no-transitions");
  }

  // Override the key "seed" CSS custom properties inline.
  // Inline style wins over :root and @variant dark CSS rules.
  el.style.setProperty("--background", theme.colors.background);
  el.style.setProperty("--foreground", theme.colors.foreground);
  el.style.setProperty("--primary", theme.colors.accent);
  el.style.setProperty("--ring", theme.colors.accent);

  // New theme-specific surface variables consumed by components that opt in.
  el.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  el.style.setProperty("--theme-editor", theme.colors.editor);
  el.style.setProperty("--theme-terminal", theme.colors.terminal);
  el.style.setProperty("--theme-statusbar", theme.colors.statusBar);

  // Drive the data attribute for CSS :has() hooks and E2E targeting.
  el.dataset.colorTheme = theme.id;

  // Toggle Tailwind's .dark class so dark: utilities continue to work.
  el.classList.toggle("dark", theme.isDark);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    el.offsetHeight;
    requestAnimationFrame(() => el.classList.remove("no-transitions"));
  }
}

// Eager apply on module load – prevents colour flash before React mounts.
applyColorTheme(getBuiltInThemeById(getStoredThemeId()));

// ── context ───────────────────────────────────────────────────────────────────

interface ColorThemeContextValue {
  themeId: BuiltInThemeId;
  theme: ThemeDefinition;
  setColorTheme: (id: BuiltInThemeId) => void;
  allThemes: readonly ThemeDefinition[];
}

const ColorThemeContext = createContext<ColorThemeContextValue | null>(null);

// ── provider ──────────────────────────────────────────────────────────────────

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [themeId, setThemeId] = useState<BuiltInThemeId>(getStoredThemeId);

  const setColorTheme = useCallback((id: BuiltInThemeId) => {
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      // Best-effort persistence only.
    }
    applyColorTheme(getBuiltInThemeById(id), true);
    setThemeId(id);
  }, []);

  // Keep DOM in sync on mount and whenever the id changes (also handles
  // cross-tab localStorage changes that trigger a re-render via storage event).
  useEffect(() => {
    applyColorTheme(getBuiltInThemeById(themeId));
  }, [themeId]);

  return (
    <ColorThemeContext.Provider
      value={{
        themeId,
        theme: getBuiltInThemeById(themeId),
        setColorTheme,
        allThemes: BUILT_IN_THEMES,
      }}
    >
      {children}
    </ColorThemeContext.Provider>
  );
}

// ── hook ──────────────────────────────────────────────────────────────────────

/**
 * Access the current named colour-palette theme and change it.
 *
 * NOTE: The existing `useTheme` hook in hooks/useTheme.ts handles
 * "light" | "dark" | "system" (OS-level colour scheme). This hook is
 * intentionally named differently to make the two concerns explicit.
 * Both can coexist — this hook also toggles the `.dark` class so that
 * Tailwind dark: utilities remain in sync with the selected palette.
 */
export function useColorTheme(): ColorThemeContextValue {
  const ctx = useContext(ColorThemeContext);
  if (!ctx) throw new Error("useColorTheme must be used within <ThemeProvider>");
  return ctx;
}

