import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_COLOR_THEME_ID,
  getBuiltInThemeById,
  isBuiltInThemeId,
  type BuiltInThemeId,
